struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    NetworkPacket packet;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read packet_id
    stream >> packet.packet_id;

    // Read username with length prefix
    stream.get_prefixed(packet.username);

    // Read score count, then use read_container for scores vector
    stream.read_container(packet.scores);

    // Read metadata as null-terminated for zero-copy
    auto metadata_view = stream.get_null_terminated();
    packet.metadata = std::string(metadata_view);

    // Skip any remaining padding bytes (if any)
    // The stream will be at the correct position after reading all data

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    PacketInfo info;

    // Create buffer adaptor and binary stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Use span() for zero-copy view of packet_id (first 4 bytes)
    auto id_span = stream.span(sizeof(uint32_t));
    std::memcpy(&info.packet_id, id_span.data(), sizeof(uint32_t));

    // Read username using prefixed adaptor to get string_view
    info.username = stream.get_prefixed_view();

    // Skip scores vector: read count, then skip the data
    uint32_t score_count;
    stream >> score_count;
    stream.skip(score_count * sizeof(uint32_t));

    return info;
}
