    hexi::buffer_adaptor adaptor(buffer);

    // Preview the first byte without advancing the read pointer
    uint8_t data_type = static_cast<uint8_t>(adaptor[0]);
    result.data_type = data_type;

    // Check available data size
    // Minimum size: 1 byte (data_type) + 4 bytes (item_count) = 5 bytes
    if (buffer.size() < 5) {
        return result; // Not enough data
    }

    // Create binary stream to read the actual data
    hexi::binary_stream stream(adaptor);

    // Read data_type and item_count
    uint8_t type;
    uint32_t item_count;
    stream >> type >> item_count;

    // Verify we have enough data for the items
    size_t item_size = (type == 0) ? sizeof(uint32_t) : sizeof(float);
    size_t required_size = 1 + 4 + (item_count * item_size);

    if (buffer.size() < required_size) {
        return result; // Not enough data
    }

    // Read items based on data type
    if (type == 0) {
        // Read integers
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else if (type == 1) {
        // Read floats
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
