#include <hexi/hexi.h>
#include <cstdint>
#include <span>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);

    // Get read pointer and check size
    const uint8_t* read_ptr = adaptor.read_ptr();
    size_t available_size = adaptor.size();

    if (available_size < sizeof(PacketHeader)) {
        return PacketHeader{0, 0, 0};
    }

    // Use binary_stream's span() for zero-copy read
    hexi::binary_stream stream(adaptor);
    auto header_span = stream.span<uint8_t>(sizeof(PacketHeader));

    PacketHeader header;
    header.magic = *reinterpret_cast<const uint32_t*>(header_span.data());
    header.version = *reinterpret_cast<const uint16_t*>(header_span.data() + 4);
    header.flags = *reinterpret_cast<const uint16_t*>(header_span.data() + 6);

    return header;
}

