PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from the input span
    hexi::buffer_adaptor adaptor(buffer);

    // Create binary stream for zero-copy operations
    hexi::binary_stream stream(adaptor);

    // Get the read pointer (buffer_adaptor pointer method)
    const auto* read_ptr = adaptor.read_data();

    // Check available data (buffer_adaptor method)
    const auto available = adaptor.readable();

    // Ensure we have enough data for the header (8 bytes total)
    constexpr std::size_t header_size = sizeof(uint32_t) + sizeof(uint16_t) + sizeof(uint16_t);
