#include <gtest/gtest.h>
#include <hexi/allocators/tls_block_allocator.h>
#include <hexi/detail/intrusive_storage.h>
#include <cstdint>

// Include the implementation
#include "implementation.hpp"

TEST(TLSAllocator, ThreadEnter) {
    tls_allocator_type<> allocator;

    enter_thread_with_allocator(allocator);

    // Allocator should be initialized after thread_enter
    auto* ptr = allocator.allocate();
    ASSERT_NE(nullptr, ptr);
    allocator.deallocate(ptr);
}

TEST(TLSAllocator, ThreadExit) {
    tls_allocator_type<> allocator;

    enter_thread_with_allocator(allocator);
    auto* ptr = allocator.allocate();

    exit_thread_with_allocator(allocator);

    // Cleanup should happen in destructor
    allocator.deallocate(ptr);
}

TEST(TLSAllocator, EnterExitCycle) {
    tls_allocator_type<> allocator;

    enter_thread_with_allocator(allocator);
    auto* ptr1 = allocator.allocate();

    exit_thread_with_allocator(allocator);

    enter_thread_with_allocator(allocator);
    auto* ptr2 = allocator.allocate();

    allocator.deallocate(ptr1);
    allocator.deallocate(ptr2);
}

