    hexi::block_allocator<std::uint64_t, element_count> allocator;

    std::cout << "=== Demonstrating block_allocator free list behavior ===\n\n";

    // Initially, all blocks are in the free list
    std::cout << "1. Initial state: All " << element_count << " blocks are in the free list\n";
    std::cout << "   Storage active count: " << allocator.storage_active_count << "\n\n";

    // Allocate some blocks - this internally uses pop() to remove from free list
    std::cout << "2. Allocating blocks removes them from the free list:\n";
    std::vector<std::uint64_t*> allocated_ptrs;
    for (size_t i = 0; i < 5; ++i) {
        auto ptr = allocator.allocate();
        allocated_ptrs.push_back(ptr);
        std::cout << "   Allocated block " << (i + 1) << " at address " << ptr << "\n";
    }
    std::cout << "   Storage active count: " << allocator.storage_active_count << "\n\n";

    // Deallocate blocks - this internally uses push() to return to free list
    std::cout << "3. Deallocating blocks returns them to the free list:\n";
    for (size_t i = 0; i < 3; ++i) {
