    hexi::block_allocator<std::uint64_t, element_count> allocator;

    std::cout << "=== Demonstrating block_allocator Free List Management ===\n\n";

    // Initially, all blocks are in the free list
    std::cout << "1. Initial state:\n";
    std::cout << "   All " << element_count << " blocks are in the free list\n";
    std::cout << "   Storage active: " << allocator.storage_active_count << "\n";
    std::cout << "   New active: " << allocator.new_active_count << "\n\n";

    // Allocate blocks - internally calls pop() to remove from free list head
    std::cout << "2. Allocating 3 blocks:\n";
    std::cout << "   (Each allocate() internally calls pop() to remove from list head)\n";

    auto* block1 = allocator.allocate();
    std::cout << "   Block 1 allocated - Active: " << allocator.storage_active_count << "\n";

    auto* block2 = allocator.allocate();
    std::cout << "   Block 2 allocated - Active: " << allocator.storage_active_count << "\n";

    auto* block3 = allocator.allocate();
    std::cout << "   Block 3 allocated - Active: " << allocator.storage_active_count << "\n\n";

    // Deallocate blocks - internally calls push() to add to free list head
    std::cout << "3. Deallocating blocks:\n";
    std::cout << "   (Each deallocate() internally calls push() to add to list head)\n";
    std::cout << "   Free list uses LIFO (stack) ordering\n";

    allocator.deallocate(block2);
    std::cout << "   Block 2 deallocated - Active: " << allocator.storage_active_count << "\n";

    allocator.deallocate(block1);
    std::cout << "   Block 1 deallocated - Active: " << allocator.storage_active_count << "\n\n";

    // Demonstrate LIFO behavior
    std::cout << "4. Demonstrating LIFO (Last-In-First-Out) behavior:\n";
    std::cout << "   Last deallocated (block1) should be returned first\n";

    auto* block4 = allocator.allocate();
    std::cout << "   New allocation matches block1? " 
              << (block4 == block1 ? "Yes (LIFO confirmed)" : "No") << "\n";

    auto* block5 = allocator.allocate();
    std::cout << "   Next allocation matches block2? " 
              << (block5 == block2 ? "Yes (LIFO confirmed)" : "No") << "\n\n";

    // Allocate beyond pre-allocated pool
    std::cout << "5. Allocating all remaining blocks:\n";
    std::vector<std::uint64_t*> blocks;
    blocks.push_back(block3);
    blocks.push_back(block4);
    blocks.push_back(block5);

    while (allocator.storage_active_count < element_count) {
        blocks.push_back(allocator.allocate());
    }

    std::cout << "   All pre-allocated blocks consumed\n";
    std::cout << "   Storage active: " << allocator.storage_active_count << "\n";

    // Allocate one more - will use heap allocation
    auto* heap_block = allocator.allocate();
    blocks.push_back(heap_block);
    std::cout << "   Allocated beyond pool (uses heap)\n";
    std::cout << "   New active: " << allocator.new_active_count << "\n\n";

    // Clean up all allocations
    std::cout << "6. Cleanup - deallocating all blocks:\n";
    for (auto* block : blocks) {
        allocator.deallocate(block);
    }

    std::cout << "   Storage active: " << allocator.storage_active_count << "\n";
    std::cout << "   New active: " << allocator.new_active_count << "\n";
    std::cout << "   Total allocations: " << allocator.total_allocs << "\n";
    std::cout << "   Total deallocations: " << allocator.total_deallocs << "\n";
    std::cout << "\n=== Free list demonstration complete ===\n";
