    auto message_id_span = stream.span(4);

    // Read the message_id from the span and convert from big-endian to native
    uint32_t big_message_id;
    std::memcpy(&big_message_id, message_id_span.data(), sizeof(uint32_t));
    header.message_id = hexi::endian::big_to_native(big_message_id);

    // Skip to advance past the header
    stream.skip(4);

    return header;
}

